function hashStr(s){let h=2166136261;for(let i=0;i<s.length;i++){h^=s.charCodeAt(i);h=Math.imul(h,16777619);}return (h>>>0);}
function mulberry32(a){return function(){a|=0;a=a+0x6D2B79F5|0;let t=Math.imul(a^a>>>15,1|a);t=t+Math.imul(t^t>>>7,61|t)^t;return ((t^t>>>14)>>>0)/4294967296;};}
function esc(s){return String(s).replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;");}
function batchim(ch){if(!ch)return false;const c=ch.charCodeAt(0)-0xAC00;return c>=0&&c<=11171&&(c%28)!==0;}
function rieul(ch){const c=ch.charCodeAt(0)-0xAC00;return c>=0&&c<=11171&&(c%28)===8;}
function inj(t,R,S){
  t=String(t).replace(/\{R\}/g,R).replace(/\{S\}/g,S);
  t=t.replace(/(.)\{eun\}/g,(m,c)=>c+(batchim(c)?"은":"는"));
  t=t.replace(/(.)\{i\}/g,(m,c)=>c+(batchim(c)?"이":"가"));
  t=t.replace(/(.)\{eul\}/g,(m,c)=>c+(batchim(c)?"을":"를"));
  t=t.replace(/(.)\{wa\}/g,(m,c)=>c+(batchim(c)?"과":"와"));
  t=t.replace(/(.)\{ro\}/g,(m,c)=>c+((batchim(c)&&!rieul(c))?"으로":"로"));
  return t;
}
function shuffled(arr,seed){const a=arr.slice();const rnd=mulberry32(seed);for(let i=a.length-1;i>0;i--){const j=Math.floor(rnd()*(i+1));[a[i],a[j]]=[a[j],a[i]];}return a;}
function pick1(arr,seed){return shuffled(arr,seed)[0];}
function pickN(arr,seed,n){return shuffled(arr,seed).slice(0,n);}

