const HEAD={s1:["{R} {J} 과외, 왜 1:1 맞춤일까요?","{R}에서 {J} 과외를 시작하기 전에","{R} {J} 과외, 이렇게 다릅니다"],curri:["학년별 {J} 커리큘럼","{R} {J}, 학년별 학습 로드맵","{J} 학년별 수업 설계"],trait:["{J} 학습의 핵심","{J}, 이렇게 접근합니다","{J} 점수를 가르는 포인트"],stuck:["{R} 학생들이 {J}에서 자주 막히는 지점","{J} 성적이 정체되는 이유","이런 학생일수록 1:1이 필요합니다"],method:["레벨업과외 {J} 학습 4단계","수업은 이렇게 진행돼요","{J} 과외 진행 4단계"],why:["학원 대신 1:1 과외를 선택하는 이유","{R}에서 학원과 1:1 과외, 무엇이 다를까","왜 1:1 과외일까요?"],faq:["{R} {J} 과외 자주 묻는 질문","자주 묻는 질문 (FAQ)"],close:["{R}에서 {J} 성적, 지금부터 바꿔보세요","{R} {J}, 무료 상담부터 시작하세요"]};

function buildArticle(R,S,subjKey,h,g,jOver){
  const sj=subPools(subjKey), J=jOver||subKo(subjKey);
  const hd=(k,off)=>inj(pick1(HEAD[k],h+off),R,J).replace(/\{J\}/g,J);
  const sec=(id,head,inner)=>`<h2 id="${id}">${esc(head)}</h2>${inner}`;
  const ps=arr=>arr.map(t=>`<p>${esc(inj(t,R,S))}</p>`).join("");
  const introArr=g?[pick1(g.intro,h).replace(/\{J\}/g,J), pick1(sj.intros,h)].concat(pickN(GENERIC.localAngle,h+11,3)):[pick1(sj.intros,h)].concat(pickN(GENERIC.localAngle,h+11,4));
  const intro=sec("s1",hd("s1",0),ps(introArr));
  const rows=(g?g.curri:sj.curri).map(c=>`<tr><td>${esc(c[0])}</td><td>${esc(c[1])}</td><td>${esc(c[2])}</td></tr>`).join("");
  const curri=sec("s2",hd("curri",1),`<p>${esc(inj("{R} {J} 과외는 학년과 목표에 따라 수업을 완전히 다르게 설계합니다.",R,S).replace(/\{J\}/g,J))}</p><table><thead><tr><th>학년</th><th>집중 영역</th><th>목표</th></tr></thead><tbody>${rows}</tbody></table>`);
  const trait=sec("s3",hd("trait",2),ps(pickN(sj.traits,h+3,3)));
  const stuck=sec("s4",hd("stuck",4),ps(pickN(sj.stuck,h+5,3)));
  const stepset=pick1(GENERIC.stepsets,h+7);
  const method=sec("s5",hd("method",6),`<p>${esc(inj(pick1(GENERIC.method,h+8),R,S))}</p><ol>${stepset.map(s=>`<li><strong>${esc(s[0])}</strong> — ${esc(s[1])}</li>`).join("")}</ol>`);
  const why=sec("s6",hd("why",9),ps(pickN(GENERIC.why,h+10,6)));
  const mids=[trait,stuck,method,why];
  const orders=[[0,1,2,3],[2,0,3,1],[0,2,1,3],[2,3,0,1],[1,2,0,3],[3,0,2,1]];
  const midHtml=orders[h%orders.length].map(i=>mids[i]).join("");
  const fqo=pickN(sj.faqs,h+13,5);
  const faq=sec("faq",hd("faq",12),fqo.map(q=>`<div class="qa"><p class="q">Q. ${esc(inj(q[0],R,S))}</p><p class="a">${esc(inj(q[1],R,S))}</p></div>`).join(""));
  const close=sec("close",hd("close",14),`<p>${esc(inj(pick1(GENERIC.closing,h+15),R,S))}</p>`);
  return {html:intro+curri+midHtml+faq+close, faqs:fqo};
}
function bc(items){
  let out=[];
  for(let i=0;i<items.length;i++){const lab=items[i][0],href=items[i][1],last=i===items.length-1;
    out.push((href&&!last)?`<a href="${href}">${esc(lab)}</a>`:`<span class="cur">${esc(lab)}</span>`);}
  return out.join('<span class="sep"> \u203A </span>');
}
