function renderCoreRegion(desc){
  if(desc.type==="regions") return regionsPage();
  if(desc.type==="sido_index") return sidoPage(desc.sd);
  const J=subKo(desc.subj);
  if(desc.type==="hub"){
    return renderCore({R:"전국",S:"전국",subj:desc.subj,path:"/"+desc.subj,
      title:`전국 ${J} 과외 | 우리 동네 1:1 맞춤 - 레벨업과외`,
      crumb:bc([["홈",BASE],[J+" 과외",null]]),
      tag:`전국 · ${J}`,titleSub:"우리 동네",areaServed:"대한민국",related:relatedHub(desc.subj)});
  } else if(desc.type==="sg"){const r=desc.r;
    return renderCore({R:r.ko,S:r.sido_s,subj:desc.subj,path:"/"+r.slug+"-"+desc.subj,
      crumb:bc([["홈",BASE],[J+" 과외","/"+desc.subj],[r.sido_s,"/"+r.sido_slug+"-"+desc.subj],[r.ko,null]]),
      tag:`${r.sido_s} · ${r.ko} · ${J}`,titleSub:r.sido_s,areaServed:r.sido_s+" "+r.ko,related:relatedRegion(desc),extra:dongListBlock(r,desc.subj,J)});
  } else if(desc.type==="sido_g"){const sd=desc.r, g=desc.g, JG=g.ko+" "+J;
    return renderCore({R:sd.s,S:sd.s,subj:desc.subj,jOver:JG,g,path:"/"+sd.slug+"-"+g.slug+"-"+desc.subj,
      crumb:bc([["홈",BASE],[J+" 과외","/"+desc.subj],[sd.s,"/"+sd.slug+"-"+desc.subj],[g.ko,null]]),
      tag:`${sd.s} · ${g.ko} · ${J}`,titleSub:sd.s,areaServed:sd.s,related:relatedGrade(desc)});
  } else if(desc.type==="sg_g"){const r=desc.r, g=desc.g, JG=g.ko+" "+J;
    return renderCore({R:r.ko,S:r.sido_s,subj:desc.subj,jOver:JG,g,path:"/"+r.slug+"-"+g.slug+"-"+desc.subj,
      crumb:bc([["홈",BASE],[J+" 과외","/"+desc.subj],[r.sido_s,"/"+r.sido_slug+"-"+desc.subj],[r.ko,"/"+r.slug+"-"+desc.subj],[g.ko,null]]),
      tag:`${r.ko} · ${g.ko} · ${J}`,titleSub:r.ko,areaServed:r.sido_s+" "+r.ko,related:relatedGrade(desc)});
  } else {const sd=desc.r;
    return renderCore({R:sd.s,S:sd.s,subj:desc.subj,path:"/"+sd.slug+"-"+desc.subj,
      crumb:bc([["홈",BASE],[J+" 과외","/"+desc.subj],[sd.s,null]]),
      tag:`${sd.s} · ${J}`,titleSub:sd.s,areaServed:sd.s,related:relatedRegion(desc),extra:sigunguListBlock(sd,desc.subj,J)});
  }
}
export function tryRenderSeoPage(path){
  const d=ROUTES.get(path);
  if(d) return renderCoreRegion(d);
  for(const sk of SUBJ_BY_LEN){
    if(path.endsWith("-"+sk)){
      const key=path.slice(1, path.length-sk.length-1);
      if(BASE_KEYS.includes(sk)){
        for(const gr of GRADES){
          if(key.endsWith("-"+gr.slug)){
            const dk=key.slice(0, key.length-gr.slug.length-1);
            const recg=dongIndex.get(dk);
            if(recg) return renderDong(recg,sk,gr);
          }
        }
      }
      const rec=dongIndex.get(key);
      if(rec) return renderDong(rec,sk);
    }
  }
  return null;
}
